+    std.debug.print("  Time per op: {d} ns\n", .{ns_per_op});
+    std.debug.print("  Target: <75 ns\n", .{});
+
+    if (ns_per_op < 75) {
+        std.debug.print("  Status: ✓ PASS\n\n", .{});
+    } else {
+        std.debug.print("  Status: ✗ FAIL (exceeded target)\n\n", .{});
+    }
+}

