+/// Helper to create send case
+pub fn sendCase(comptime T: type, chan: anytype, value: *T) Select.Case {
+    return Select.Case{
+        .send = .{
+            .chan = @ptrCast(chan),
+            .value = @ptrCast(value),
+            .value_size = @sizeOf(T),
+        },
+    };
