+
+    /// Wake the task (by reference)
+    pub fn wakeByRef(self: *const Waker) void {
+        self.vtable.wake_by_ref(self.task);
+    }
+
+    /// Drop the waker
+    pub fn drop(self: Waker) void {
+        self.vtable.drop(self.task);
+    }
