+    const testing = std.testing;
+
+    if (builtin.os.tag == .linux or builtin.os.tag == .macos) {
+        try testing.expect(isSignalPreemptionSupported());
+    } else {
+        try testing.expect(!isSignalPreemptionSupported());
+    }
+}
+
+test "Mark processor for preemption" {
