+
+        if (has_avx2) {
+            return x86_64.findSpecialCharAvx2(data, offset);
+        }
+    } else if (comptime aarch64_available) {
+        return aarch64.findSpecialCharNeon(data, offset);
+    }
+
+    // Fallback to scalar
+    return scalar.findSpecialChar(data, offset);
